import os

def get_total_log_size():
    size = 0
    for root, _, filenames in os.walk('logs'):
        for f in filenames:
            filepath = os.path.join(root, f)
            try:
                size += os.path.getsize(filepath)
            except IOError:
                pass
    return size

def list_all_log_files(path=None):
    if path is None:
        path = 'logs'
    log_files = []
    for root, _, filenames in os.walk(path):
        for f in filenames:
            filepath = os.path.join(root, f)
            if os.path.islink(filepath):
                continue
            try:
                if os.path.getsize(filepath) > 0:
                    log_files.append(filepath)
            except IOError:
                pass
    return log_files
